+using System.ComponentModel;
+using System.Net.Http.Json;
+using System.Text.Json.Serialization;
+using Microsoft.Extensions.AI;
+
+namespace ResearchAgent.Tools;
+
+/// <summary>
+/// Provides a web search tool that queries Wikipedia's public API.
+/// No API key required — uses the MediaWiki Action API for search and content retrieval.
+/// </summary>
+public sealed class WebSearchTool
+{
+    private readonly HttpClient _httpClient;
+
+    public WebSearchTool(HttpClient httpClient)
+    {
+        _httpClient = httpClient;
+        _httpClient.BaseAddress ??= new Uri("https://en.wikipedia.org/");
+        _httpClient.DefaultRequestHeaders.UserAgent.TryParseAdd("ResearchAgent/1.0");
+    }
+
+    [Description("Search the web for information on a topic. Returns a list of relevant result titles and snippets.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query to look up")] string query,
+        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
+    {
+        maxResults = Math.Clamp(maxResults, 1, 10);
+
+        var url = $"w/api.php?action=query&list=search&srsearch={Uri.EscapeDataString(query)}" +
+                  $"&srlimit={maxResults}&format=json&utf8=1";
+
+        var response = await _httpClient.GetFromJsonAsync<WikiSearchResponse>(url);
+
+        if (response?.Query?.Search is not { Count: > 0 })
+        {
+            return $"No results found for '{query}'.";
+        }
+
+        var results = response.Query.Search.Select((r, i) =>
+            $"[{i + 1}] {r.Title}\n    {StripHtml(r.Snippet)}");
+
+        return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
+    }
+
+    [Description("Fetch the full content summary of a specific topic page. Use after searching to get detailed information.")]
+    public async Task<string> FetchPageContent(
+        [Description("The exact title of the page to fetch")] string title)
+    {
+        var url = $"w/api.php?action=query&titles={Uri.EscapeDataString(title)}" +
+                  "&prop=extracts&exintro=0&explaintext=1&exsectionformat=plain" +
+                  "&exchars=3000&format=json&utf8=1";
+
+        var response = await _httpClient.GetFromJsonAsync<WikiPageResponse>(url);
+        var page = response?.Query?.Pages?.Values.FirstOrDefault();
+
+        if (page is null || page.PageId == -1 || string.IsNullOrWhiteSpace(page.Extract))
+        {
+            return $"Could not fetch content for '{title}'. Try a different title from search results.";
+        }
+
+        return $"--- {page.Title} ---\n\n{page.Extract}";
+    }
+
+    private static string StripHtml(string? html) =>
+        string.IsNullOrEmpty(html)
+            ? string.Empty
+            : System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", string.Empty);
+
+    // JSON models for Wikipedia API responses
+    private sealed class WikiSearchResponse
+    {
+        [JsonPropertyName("query")]
+        public WikiQueryResult? Query { get; set; }
+    }
+
+    private sealed class WikiQueryResult
+    {
+        [JsonPropertyName("search")]
+        public List<WikiSearchResult>? Search { get; set; }
+
+        [JsonPropertyName("pages")]
+        public Dictionary<string, WikiPage>? Pages { get; set; }
+    }
+
+    private sealed class WikiSearchResult
+    {
+        [JsonPropertyName("title")]
+        public string Title { get; set; } = string.Empty;
+
+        [JsonPropertyName("snippet")]
+        public string? Snippet { get; set; }
+    }
+
+    private sealed class WikiPageResponse
+    {
+        [JsonPropertyName("query")]
+        public WikiQueryResult? Query { get; set; }
+    }
+
+    private sealed class WikiPage
+    {
+        [JsonPropertyName("pageid")]
+        public int PageId { get; set; } = -1;
+
+        [JsonPropertyName("title")]
+        public string Title { get; set; } = string.Empty;
+
+        [JsonPropertyName("extract")]
+        public string? Extract { get; set; }
+    }
+}
