using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client through MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tool instances ---
var httpClient = new HttpClient();
var webSearch = new WebSearchTool(httpClient);
var notes = new NoteTool();

// --- Register tools via AIFunctionFactory ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(webSearch.FetchPageContent),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.ListNotes),
    AIFunctionFactory.Create(notes.GetNote),
    AIFunctionFactory.Create(notes.GetAllNotes),
};

// --- Build the research agent with Microsoft Agent Framework ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = [.. tools],
        },
    });

// --- System instructions ---
var systemMessage = new ChatMessage(ChatRole.System, """
    You are a thorough research assistant. When given a topic:

    1. Use SearchWeb to find relevant information (try multiple queries for breadth).
    2. Use FetchPageContent to read detailed content from promising results.
    3. Use SaveNote to record key findings as you go — include specific facts, dates, and figures.
    4. After gathering enough information, use GetAllNotes to review your notes.
    5. Write a well-structured summary with sections, synthesizing all your findings.

    Be thorough but concise. Cite your sources. Always take at least 2-3 notes before summarizing.
    """);

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 AI Research Agent           ║");
Console.WriteLine("║  Enter a topic to research, or       ║");
Console.WriteLine("║  type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic: ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching '{topic}'... (the agent will search, take notes, and summarize)\n");
    Console.ResetColor();

    try
    {
        var session = await agent.CreateSessionAsync();
        var userMessage = new ChatMessage(ChatRole.User,
            $"Research the following topic thoroughly and provide a comprehensive summary: {topic}");

        // Stream the agent's final response
        var hasOutput = false;
        await foreach (var update in agent.RunStreamingAsync(
            [systemMessage, userMessage], session))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                if (!hasOutput)
                {
                    Console.ForegroundColor = ConsoleColor.Green;
                    Console.WriteLine("── Research Summary ──────────────────────");
                    Console.ResetColor();
                    hasOutput = true;
                }

                Console.Write(update.Text);
            }
        }

        if (hasOutput)
        {
            Console.WriteLine();
            Console.ForegroundColor = ConsoleColor.Green;
            Console.WriteLine("──────────────────────────────────────────");
            Console.ResetColor();
        }
        else
        {
            Console.WriteLine("No response generated.");
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

httpClient.Dispose();

